# deploy_cogniadev_fase1.ps1
# Crea el proyecto Cognia Dev (Fase 1) y lo sube a un nuevo repo

# 1. Crear estructura de carpetas
New-Item -ItemType Directory -Force -Path (Join-Path $PSScriptRoot "app\routes") | Out-Null
New-Item -ItemType Directory -Force -Path (Join-Path $PSScriptRoot "app\static") | Out-Null

$b64 = ''
[System.IO.File]::WriteAllBytes((Join-Path $PSScriptRoot "app\__init__.py"), [System.Convert]::FromBase64String($b64))
Write-Host "  OK app/__init__.py"

$b64 = ''
[System.IO.File]::WriteAllBytes((Join-Path $PSScriptRoot "app\routes\__init__.py"), [System.Convert]::FromBase64String($b64))
Write-Host "  OK app/routes/__init__.py"

$b64 = ''
[System.IO.File]::WriteAllBytes((Join-Path $PSScriptRoot "app\main.py"), [System.Convert]::FromBase64String($b64))
Write-Host "  OK app/main.py"

$b64 = ''
[System.IO.File]::WriteAllBytes((Join-Path $PSScriptRoot "app\ollama_client.py"), [System.Convert]::FromBase64String($b64))
Write-Host "  OK app/ollama_client.py"

$b64 = ''
[System.IO.File]::WriteAllBytes((Join-Path $PSScriptRoot "app\routes\health.py"), [System.Convert]::FromBase64String($b64))
Write-Host "  OK app/routes/health.py"

$b64 = ''
[System.IO.File]::WriteAllBytes((Join-Path $PSScriptRoot "app\routes\generar.py"), [System.Convert]::FromBase64String($b64))
Write-Host "  OK app/routes/generar.py"

$b64 = ''
[System.IO.File]::WriteAllBytes((Join-Path $PSScriptRoot "app\routes\corregir.py"), [System.Convert]::FromBase64String($b64))
Write-Host "  OK app/routes/corregir.py"

$b64 = ''
[System.IO.File]::WriteAllBytes((Join-Path $PSScriptRoot "app\static\index.html"), [System.Convert]::FromBase64String($b64))
Write-Host "  OK app/static/index.html"

$b64 = 'ZmFzdGFwaT49MC4xMTEuMAp1dmljb3JuW3N0YW5kYXJkXT49MC4yOS4wCnB5ZGFudGljPj0yLjAuMApweXRob24tbXVsdGlwYXJ0Pj0wLjAuOQo='
[System.IO.File]::WriteAllBytes((Join-Path $PSScriptRoot "requirements.txt"), [System.Convert]::FromBase64String($b64))
Write-Host "  OK requirements.txt"

# 2. README
$readme = @'
# Cognia Dev - Fase 1

## Inicio rapido
```
pip install -r requirements.txt
uvicorn app.main:app --host 0.0.0.0 --port 8001 --reload
```
Luego abre http://localhost:8001 en tu navegador.

## Requisitos
- Ollama corriendo localmente con qwen2.5-coder:7b
- Python 3.10+
'@
[System.IO.File]::WriteAllText((Join-Path $PSScriptRoot "README.md"), $readme)
Write-Host "  OK README.md"

# 3. Git
if (-not (Test-Path (Join-Path $PSScriptRoot ".git"))) {
  git init
  git branch -M main
}
git add .
git commit -m "feat: Cognia Dev Fase 1 - API base generar/corregir C# + frontend"

Write-Host ""
Write-Host "Cognia Dev Fase 1 lista."
Write-Host "Pasos siguientes:"
Write-Host "  1. Crea el repo en GitHub: https://github.com/new (nombre sugerido: cognia_dev)"
Write-Host "  2. git remote add origin https://github.com/tomascomenta-blip/cognia_dev.git"
Write-Host "  3. git push -u origin main"
Write-Host "  4. pip install -r requirements.txt"
Write-Host "  5. uvicorn app.main:app --host 0.0.0.0 --port 8001 --reload"
Write-Host "  6. Abre http://localhost:8001"